import { useState } from "react";
import MedicineSearch from "../components/MedicineSearch";
import DoseResult from "../components/DoseResult";
import AIChatBot from "../components/AIChatBot";
// ❌ Removed PatientProfileCard import
import { Alert, Spinner, Card } from "../components/UI";
import { api } from "../services/api";

export default function CalculatorPage() {
  const [selectedMed, setSelectedMed] = useState(null);
  // ❌ Removed patientProfile state
  const [weight, setWeight] = useState("");
  const [ageYears, setAgeYears] = useState("");
  const [ageMonths, setAgeMonths] = useState("");
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);
  const [loading, setLoading] = useState(false);
  const [showAIChat, setShowAIChat] = useState(false);
  const [aiSuggestion, setAiSuggestion] = useState(null);

  const totalMonths = () =>
    (parseFloat(ageYears) || 0) * 12 + (parseFloat(ageMonths) || 0);

  const handleCalculate = async () => {
    if (!selectedMed || !weight) return;
    setLoading(true);
    setError(null);
    setResult(null);
    try {
      const data = await api.calculateDose({
        medicine_id: selectedMed.id,
        weight_kg: parseFloat(weight),
        age_months: totalMonths() || 1,
        // ❌ Removed conditions dependency
      });
      setResult(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleAISuggestion = (suggestion) => {
    setAiSuggestion(suggestion);
    if (suggestion.medicine) {
      setSelectedMed(suggestion.medicine);
    }
  };

  return (
    <div className="page">
      <div className="page-header">
        <h1>AI-Powered Dose Calculator</h1>
        <p>Smart dosing with predictive analytics and clinical intelligence</p>
      </div>

      <div className="two-col-layout">
        {/* Left Column */}
        <div className="left-col">

          {/* ❌ Patient Profile Card Removed Completely */}

          <Card className="ai-chat-card">
            <div className="card-header">
              <h3>AI Assistant</h3>
              <button
                className="btn-ghost btn-sm"
                onClick={() => setShowAIChat(!showAIChat)}
              >
                {showAIChat ? 'Hide' : 'Chat'}
              </button>
            </div>
            {showAIChat && (
              <AIChatBot
                // ❌ Removed patientContext
                onRecommendation={handleAISuggestion}
              />
            )}
          </Card>
        </div>

        {/* Right Column */}
        <div className="right-col">
          <Card>
            <h2 className="card-heading">Medication Details</h2>

            {aiSuggestion && (
              <div className="ai-suggestion">
                <div className="suggestion-content">
                  <strong>🤖 AI Suggestion</strong>
                  <p>{aiSuggestion.reasoning || 'Based on input'}</p>
                </div>
                <button
                  className="btn-sm btn-primary"
                  onClick={() => {
                    if (aiSuggestion.medicine) {
                      setSelectedMed(aiSuggestion.medicine);
                    }
                  }}
                >
                  Apply
                </button>
              </div>
            )}

            <div className="field">
              <label className="field-label">Medicine</label>
              <MedicineSearch
                value={selectedMed}
                onSelect={(med) => {
                  setSelectedMed(med);
                  setResult(null);
                  setError(null);
                }}
                placeholder="Type medicine name..."
              />
            </div>

            <div className="field">
              <label className="field-label">Weight (kg)</label>
              <input
                className="input"
                type="number"
                min="0.5"
                step="0.1"
                placeholder="e.g., 70"
                value={weight}
                onChange={(e) => setWeight(e.target.value)}
              />
            </div>

            <div className="field">
              <label className="field-label">Age</label>
              <div className="row-2">
                <input
                  className="input"
                  type="number"
                  min="0"
                  placeholder="Years"
                  value={ageYears}
                  onChange={(e) => setAgeYears(e.target.value)}
                />
                <input
                  className="input"
                  type="number"
                  min="0"
                  max="11"
                  placeholder="Months"
                  value={ageMonths}
                  onChange={(e) => setAgeMonths(e.target.value)}
                />
              </div>
            </div>

            <button
              className="btn-primary btn-large"
              onClick={handleCalculate}
              disabled={!selectedMed || !weight || loading}
            >
              {loading ? <Spinner /> : 'Calculate Safe Dose →'}
            </button>

            {error && (
              <Alert type="danger" style={{ marginTop: '16px' }}>
                {error}
              </Alert>
            )}
          </Card>

          {result && <DoseResult result={result} />}
        </div>
      </div>
    </div>
  );
}
